// BAD - GC doesn't know about this pointer
AActor* MyActor;

// GOOD - GC tracks this reference
UPROPERTY()
AActor* MyActor;

// GOOD - weak reference for optional/non-owning refs
TWeakObjectPtr<AActor> MyActorWeak;

// BAD - crashes on CDO construction
AMyActor::AMyActor() {
    GetWorld()->SpawnActor<AActor>();  // GetWorld() is null for CDO
}

// GOOD - gameplay logic in BeginPlay
void AMyActor::BeginPlay() {
    Super::BeginPlay();
    GetWorld()->SpawnActor<AOtherActor>(OtherActorClass);
}

// check() - fatal, crashes in debug/development builds
check(MyPtr != nullptr);

// ensure() - logs callstack, continues execution (fires once)
if (ensure(MyPtr != nullptr)) {
    MyPtr->DoSomething();
}

// verify() - like check but expression always evaluates
verify(ImportantFunction());  // ImportantFunction runs even in shipping

void AMyActor::EndPlay(const EEndPlayReason::Type EndPlayReason) {
    GetWorldTimerManager().ClearAllTimersForObject(this);
    if (MyDelegate.IsBound()) MyDelegate.Unbind();
    Super::EndPlay(EndPlayReason);
}

// BAD
AActor* First = MyArray[0];  // crashes if empty

// GOOD
if (MyArray.IsValidIndex(0)) {
    AActor* First = MyArray[0];
}

// Removing while iterating - go backwards
for (int32 i = MyArray.Num() - 1; i >= 0; i--) {
    if (ShouldRemove(MyArray[i])) MyArray.RemoveAt(i);
}

// BAD - raw binding won't auto-unbind
MyDelegate.AddRaw(this, &AMyActor::OnEvent);

// GOOD - auto-unbinds when this UObject is destroyed
MyDelegate.AddUObject(this, &AMyActor::OnEvent);

// GOOD - weak pointer in lambda
TWeakObjectPtr<AMyActor> WeakThis(this);
MyDelegate.AddLambda([WeakThis]() {
    if (WeakThis.IsValid()) WeakThis->OnEvent();
});

// Do heavy work on background thread, update UObject on game thread
AsyncTask(ENamedThreads::AnyBackgroundThreadNormalTask, [this]() {
    FString Result = DoExpensiveWork();

    AsyncTask(ENamedThreads::GameThread, [this, Result]() {
        MyTextBlock->SetText(FText::FromString(Result));
    });
});
